pub struct AriaRelevant {
    /// Node additions are relevant.
    pub additions: bool,

    /// Node removals are relevant.
    pub removals: bool,

    /// Text content changes are relevant.
    pub text: bool,
}

impl Display for AriaRelevant {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        let mut parts = Vec::new();

        if self.additions {
            parts.push("additions");
        }

        if self.removals {
            parts.push("removals");
        }

        if self.text {
            parts.push("text");
        }

        if parts.is_empty() {
            // All-false returns empty string so the attribute is omitted, letting
            // the browser apply its default (`additions text`).
            return write!(f, "");
        }

        let mut first = true;

        for part in &parts {
            if first {
                first = false;
            } else {
                f.write_str(" ")?;
            }

            f.write_str(part)?;
        }

        Ok(())
    }
}

impl Default for AriaRelevant {
    fn default() -> Self {
        Self {
            additions: true,
            removals: false,
            text: true,
        }
    }
}

