pub struct Props {
    /// Component instance ID.
    pub id: String,
    /// The politeness of the announcements.
    pub politeness: AriaPoliteness,
    /// Whether the live region should be announced as atomic.
    pub atomic: bool,
    /// The relevant changes for `aria-relevant`.
